easy.solution:
def char_freq(s):
    freq = {}
    for c in s:
        freq[c] = freq.get(c, 0) + 1
    return freq

medium.solution:
def get_passing(names, scores):
    passing = []
    for name, score in zip(names, scores):
        if score >= 50:
            passing.append(f'{name}: {score}')
    return passing

hard.solution:
def transpose(matrix):
    if not matrix: return []
    rows, cols = len(matrix), len(matrix[0])
    result = [[0]*rows for _ in range(cols)]
    for r in range(rows):
        for c in range(cols):
            result[c][r] = matrix[r][c]
    return result

